  "phaser_config": {
    "load_method": "spritesheet",
    "load_code_template": "this.load.spritesheet(key, path, { frameWidth, frameHeight });",
    "character_path_template": "assets/PixelAdventure_1_Free/Main_Characters/{SKIN}/{FILE}",
    "shared_path_template": "assets/PixelAdventure_1_Free/Main_Characters/{FILE}",
    "prd_load_code": "// ===== K12横版闯关游戏 Phaser.js 资源加载代码 =====\n// 【玩家角色】推荐使用 Mask_Dude（面具小子）\nthis.load.spritesheet('player_idle',   'assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Idle_(352x32)[frames=11].png',   { frameWidth: 32, frameHeight: 32 });\nthis.load.spritesheet('player_run',    'assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Run_(384x32)[frames=12].png',    { frameWidth: 32, frameHeight: 32 });\nthis.load.image(      'player_jump',   'assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Jump_(32x32).png');\nthis.load.image(      'player_fall',   'assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Fall_(32x32).png');\nthis.load.spritesheet('player_hit',    'assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Hit_(224x32)[frames=7].png',     { frameWidth: 32, frameHeight: 32 });\n// 【敌人角色】使用 Virtual_Guy（虚拟小子）皮肤作为敌人\nthis.load.spritesheet('enemy_idle',    'assets/PixelAdventure_1_Free/Main_Characters/Virtual_Guy/Idle_(352x32)[frames=11].png',  { frameWidth: 32, frameHeight: 32 });\nthis.load.spritesheet('enemy_run',     'assets/PixelAdventure_1_Free/Main_Characters/Virtual_Guy/Run_(384x32)[frames=12].png',   { frameWidth: 32, frameHeight: 32 });\n// 【收集物：星星/水果】使用 Strawberry 作为星星替代\nthis.load.spritesheet('star',          'assets/PixelAdventure_1_Free/Items/Fruits/Strawberry_(544x32).png',                     { frameWidth: 32, frameHeight: 32 });\nthis.load.spritesheet('star_collected','assets/PixelAdventure_1_Free/Items/Fruits/Collected_(192x32).png',                      { frameWidth: 32, frameHeight: 32 });\n// 【检查点】\nthis.load.image(      'checkpoint_off','assets/PixelAdventure_1_Free/Items/Checkpoints/Checkpoint/Checkpoint_(No_Flag)_(64x64).png');\nthis.load.spritesheet('checkpoint_idle','assets/PixelAdventure_1_Free/Items/Checkpoints/Checkpoint/Checkpoint_(Flag_Idle)_(640x64).png', { frameWidth: 64, frameHeight: 64 });\nthis.load.spritesheet('checkpoint_on', 'assets/PixelAdventure_1_Free/Items/Checkpoints/Checkpoint/Checkpoint_(Flag_Out)_(1664x64).png',  { frameWidth: 64, frameHeight: 64 });\n// 【终点】\nthis.load.image(      'end_idle',      'assets/PixelAdventure_1_Free/Items/Checkpoints/End/End_(Idle)_(64x64).png');\nthis.load.spritesheet('end_pressed',   'assets/PixelAdventure_1_Free/Items/Checkpoints/End/End_(Pressed)_(512x64).png',          { frameWidth: 64, frameHeight: 64 });\n// 【背景】\nthis.load.image(      'bg_blue',       'assets/PixelAdventure_1_Free/Background/Blue_(64x64).png');\nthis.load.image(      'bg_green',      'assets/PixelAdventure_1_Free/Background/Green_(64x64).png');",
    "prd_animation_code": "// ===== 动画创建代码（在 create() 中调用）=====\n// 玩家待机\nthis.anims.create({ key: 'player_idle', frames: this.anims.generateFrameNumbers('player_idle', { start: 0, end: 10 }), frameRate: 11, repeat: -1 });\n// 玩家奔跑\nthis.anims.create({ key: 'player_run',  frames: this.anims.generateFrameNumbers('player_run',  { start: 0, end: 11 }), frameRate: 12, repeat: -1 });\n// 玩家受击\nthis.anims.create({ key: 'player_hit',  frames: this.anims.generateFrameNumbers('player_hit',  { start: 0, end: 6  }), frameRate: 7,  repeat: 0  });\n// 敌人待机\nthis.anims.create({ key: 'enemy_idle',  frames: this.anims.generateFrameNumbers('enemy_idle',  { start: 0, end: 10 }), frameRate: 11, repeat: -1 });\n// 敌人巡逻\nthis.anims.create({ key: 'enemy_run',   frames: this.anims.generateFrameNumbers('enemy_run',   { start: 0, end: 11 }), frameRate: 12, repeat: -1 });\n// 星星旋转\nthis.anims.create({ key: 'star_spin',   frames: this.anims.generateFrameNumbers('star',         { start: 0, end: 16 }), frameRate: 17, repeat: -1 });\n// 星星收集\nthis.anims.create({ key: 'star_collect',frames: this.anims.generateFrameNumbers('star_collected',{ start: 0, end: 5  }), frameRate: 6,  repeat: 0  });\n// 检查点激活\nthis.anims.create({ key: 'checkpoint_activate', frames: this.anims.generateFrameNumbers('checkpoint_on', { start: 0, end: 25 }), frameRate: 13, repeat: 0 });\nthis.anims.create({ key: 'checkpoint_wave',     frames: this.anims.generateFrameNumbers('checkpoint_idle',{ start: 0, end: 9  }), frameRate: 10, repeat: -1 });\n// 终点按下\nthis.anims.create({ key: 'end_press',   frames: this.anims.generateFrameNumbers('end_pressed',  { start: 0, end: 7  }), frameRate: 8,  repeat: 0  });",
    "prd_usage_snippets": {
      "player_sprite": "// 创建玩家精灵（32x32像素，建议显示尺寸64x64适配64px网格）\nconst player = this.physics.add.sprite(100, 400, 'player_idle');\nplayer.setScale(2); // 放大2倍至64x64\nplayer.play('player_idle');",
      "player_state_machine": "// 玩家动画状态切换\nif (player.body.blocked.down) {\n  if (Math.abs(player.body.velocity.x) > 10) player.play('player_run', true);\n  else player.play('player_idle', true);\n} else {\n  if (player.body.velocity.y < 0) player.setTexture('player_jump');\n  else player.setTexture('player_fall');\n}",
      "enemy_sprite": "// 创建敌人精灵（使用 Virtual_Guy 皮肤）\nconst enemy = this.physics.add.sprite(x, y, 'enemy_idle');\nenemy.setScale(2);\nenemy.play('enemy_idle');",
      "star_sprite": "// 创建星星（水果收集物）\nconst star = this.physics.add.staticSprite(x, y, 'star');\nstar.setScale(2);\nstar.play('star_spin');",
      "star_collect": "// 收集星星回调\nfunction collectStar(player, star) {\n  star.play('star_collect');\n  star.once('animationcomplete', () => star.destroy());\n  starCount++;\n  starText.setText(starCount + '/5');\n}",
      "checkpoint_sprite": "// 创建检查点（初始无旗状态）\nconst cp = this.physics.add.staticSprite(x, y, 'checkpoint_off');\ncp.setScale(2);\n// 激活检查点\nfunction activateCheckpoint(cp) {\n  cp.setTexture('checkpoint_on');\n  cp.play('checkpoint_activate');\n  cp.once('animationcomplete', () => cp.play('checkpoint_wave'));\n}",
      "end_sprite": "// 创建终点\nconst endPoint = this.physics.add.staticSprite(x, y, 'end_idle');\nendPoint.setScale(2);\n// 到达终点\nfunction reachEnd(player, end) {\n  if (starCount >= 5) {\n    end.setTexture('end_pressed');\n    end.play('end_press');\n    // 触发胜利\n  }\n}",
      "background": "// 铺设背景（64x64 tile 重复铺满屏幕）\nconst bg = this.add.tileSprite(0, 0, 800, 600, 'bg_blue').setOrigin(0, 0);"
    }
  },
