import { create } from 'zustand';

export type GameStatus = 'start' | 'playing' | 'win' | 'lose';

interface GameState {
  status: GameStatus;
  score: number;
  setStatus: (status: GameStatus) => void;
  addScore: (delta: number) => void;
  resetGame: () => void;
}

export const useGameStore = create<GameState>((set) => ({
  status: 'start',
  score: 0,
  setStatus: (status) => set({ status }),
  addScore: (delta) => set((state) => ({ score: state.score + delta })),
  resetGame: () => set({ status: 'playing', score: 0 }),
}));

// Game parameters and constants
export const GAME_WIDTH = 800;
export const GAME_HEIGHT = 600;

export const TILE_SIZE = 64; // 64px grid

// Physics
export const GRAVITY = 1000;
export const PLAYER_SPEED = 300;
export const JUMP_VELOCITY = -550; // Jump strength
export const VARIABLE_JUMP_MULTIPLIER = 0.5; // When releasing jump early

// Mechanics
export const COYOTE_TIME = 150; // ms
export const JUMP_BUFFER_TIME = 150; // ms

// Level
export const STARS_TO_WIN = 5;

import { EventBus } from './EventBus';
import Phaser from 'phaser';

export function startScene(scene: Phaser.Scene, key: string, data?: object) {
  scene.scene.start(key, data);
  EventBus.emit('scene-changed', { key, data });
}

import { Scene } from 'phaser';

export class Boot extends Scene {
  constructor() {
    super('Boot');
  }

  preload() {
    // We can load some initial loading screen assets here if needed
  }

  create() {
    this.scene.start('Preloader');
  }
}

// Background
import bgBlue from '../assets/PixelAdventure_1_Free/Background/Blue_(64x64).png';

// Player
import playerIdle from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Idle_(352x32)[frames=11].png';
import playerRun from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Run_(384x32)[frames=12].png';
import playerJump from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Jump_(32x32).png';
import playerFall from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Fall_(32x32).png';
import playerHit from '../assets/PixelAdventure_1_Free/Main_Characters/Mask_Dude/Hit_(224x32)[frames=7].png';

// Enemy
import enemyIdle from '../assets/PixelAdventure_1_Free/Main_Characters/Virtual_Guy/Idle_(352x32)[frames=11].png';
import enemyRun from '../assets/PixelAdventure_1_Free/Main_Characters/Virtual_Guy/Run_(384x32)[frames=12].png';

// Items
import star from '../assets/PixelAdventure_1_Free/Items/Fruits/Strawberry_(544x32).png';
import starCollected from '../assets/PixelAdventure_1_Free/Items/Fruits/Collected_(192x32).png';

// Checkpoints / End
import checkpointOff from '../assets/PixelAdventure_1_Free/Items/Checkpoints/Checkpoint/Checkpoint_(No_Flag)_(64x64).png';
import checkpointIdle from '../assets/PixelAdventure_1_Free/Items/Checkpoints/Checkpoint/Checkpoint_(Flag_Idle)_(640x64).png';
import checkpointOn from '../assets/PixelAdventure_1_Free/Items/Checkpoints/Checkpoint/Checkpoint_(Flag_Out)_(1664x64).png';
import endIdle from '../assets/PixelAdventure_1_Free/Items/Checkpoints/End/End_(Idle)_(64x64).png';
import endPressed from '../assets/PixelAdventure_1_Free/Items/Checkpoints/End/End_(Pressed)_(512x64).png';

export const GameAssets = {
  bgBlue,
  playerIdle,
  playerRun,
  playerJump,
  playerFall,
  playerHit,
  enemyIdle,
  enemyRun,
  star,
  starCollected,
  checkpointOff,
  checkpointIdle,
  checkpointOn,
  endIdle,
  endPressed
};

import { Scene } from 'phaser';
import { GameAssets } from '../assets';

export class Preloader extends Scene {
  constructor() {
    super('Preloader');
  }

  preload() {
    // Generate fallback textures on error
    this.load.on('loaderror', (file: any) => {
      const g = this.add.graphics();
      const w = this.game.config.width as number;
      const h = this.game.config.height as number;
      g.fillGradientStyle(0x667788, 0x334455, 0x334455, 0x667788);
      g.fillRect(0, 0, w, h);
      g.generateTexture(file.key, w, h);
      g.destroy();
    });

    // Player
    this.load.spritesheet('player_idle', GameAssets.playerIdle, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('player_run', GameAssets.playerRun, { frameWidth: 32, frameHeight: 32 });
    this.load.image('player_jump', GameAssets.playerJump);
    this.load.image('player_fall', GameAssets.playerFall);
    this.load.spritesheet('player_hit', GameAssets.playerHit, { frameWidth: 32, frameHeight: 32 });

    // Enemy
    this.load.spritesheet('enemy_idle', GameAssets.enemyIdle, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('enemy_run', GameAssets.enemyRun, { frameWidth: 32, frameHeight: 32 });

    // Items
    this.load.spritesheet('star', GameAssets.star, { frameWidth: 32, frameHeight: 32 });
    this.load.spritesheet('star_collected', GameAssets.starCollected, { frameWidth: 32, frameHeight: 32 });

    // Checkpoint
    this.load.image('checkpoint_off', GameAssets.checkpointOff);
    this.load.spritesheet('checkpoint_idle', GameAssets.checkpointIdle, { frameWidth: 64, frameHeight: 64 });
    this.load.spritesheet('checkpoint_on', GameAssets.checkpointOn, { frameWidth: 64, frameHeight: 64 });

    // End
    this.load.image('end_idle', GameAssets.endIdle);
    this.load.spritesheet('end_pressed', GameAssets.endPressed, { frameWidth: 64, frameHeight: 64 });

    // Background
    this.load.image('bg_blue', GameAssets.bgBlue);
  }

  create() {
    this.createAnimations();
    this.scene.start('Game');
  }

  createAnimations() {
    this.anims.create({ key: 'player_idle', frames: this.anims.generateFrameNumbers('player_idle', { start: 0, end: 10 }), frameRate: 11, repeat: -1 });
    this.anims.create({ key: 'player_run', frames: this.anims.generateFrameNumbers('player_run', { start: 0, end: 11 }), frameRate: 12, repeat: -1 });
    this.anims.create({ key: 'player_hit', frames: this.anims.generateFrameNumbers('player_hit', { start: 0, end: 6 }), frameRate: 7, repeat: 0 });
    this.anims.create({ key: 'enemy_idle', frames: this.anims.generateFrameNumbers('enemy_idle', { start: 0, end: 10 }), frameRate: 11, repeat: -1 });
    this.anims.create({ key: 'enemy_run', frames: this.anims.generateFrameNumbers('enemy_run', { start: 0, end: 11 }), frameRate: 12, repeat: -1 });
    this.anims.create({ key: 'star_spin', frames: this.anims.generateFrameNumbers('star', { start: 0, end: 16 }), frameRate: 17, repeat: -1 });
    this.anims.create({ key: 'star_collect', frames: this.anims.generateFrameNumbers('star_collected', { start: 0, end: 5 }), frameRate: 6, repeat: 0 });
    this.anims.create({ key: 'checkpoint_activate', frames: this.anims.generateFrameNumbers('checkpoint_on', { start: 0, end: 25 }), frameRate: 13, repeat: 0 });
    this.anims.create({ key: 'checkpoint_wave', frames: this.anims.generateFrameNumbers('checkpoint_idle', { start: 0, end: 9 }), frameRate: 10, repeat: -1 });
    this.anims.create({ key: 'end_press', frames: this.anims.generateFrameNumbers('end_pressed', { start: 0, end: 7 }), frameRate: 8, repeat: 0 });
  }
}

