import React, { useEffect, useRef } from 'react';
import Phaser from 'phaser';
import { config } from './game/main';
import { useGameStore } from './game/model/store';
import { EventBus } from './game/EventBus';

export default function App() {
  const initialized = useRef(false);
  const status = useGameStore((state) => state.status);
  const score = useGameStore((state) => state.score);
  const setStatus = useGameStore((state) => state.setStatus);
  const resetGame = useGameStore((state) => state.resetGame);

  useEffect(() => {
    if (initialized.current) return;
    initialized.current = true;

    const game = new Phaser.Game(config);

    // Listen to game events
    EventBus.on('win', () => {
      setStatus('win');
    });

    return () => {
      game.destroy(true);
      initialized.current = false;
      EventBus.off('win');
    };
  }, [setStatus]);

  return (
    <div className="relative w-screen h-screen overflow-hidden bg-[#87CEEB] select-none font-sans font-bold text-gray-800">
      {/* Phaser Game Container */}
      <div id="game-container" className="w-full h-full" />

      {/* Start Screen */}
      {status === 'start' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-10">
          <div className="bg-[#8CC63F] border-4 border-[#333333] shadow-[8px_8px_0_0_#333333] p-8 flex flex-col items-center max-w-md w-[90%] text-center">
            <h1 className="text-4xl text-white mb-6 text-shadow-sm" style={{textShadow: '2px 2px 0 #333333'}}>K12横版闯关</h1>
            <p className="text-white mb-8 text-lg" style={{textShadow: '1px 1px 0 #333333'}}>按键盘左右键移动，空格键跳跃。<br/>收集5颗星星即可通关！</p>
            <button 
              className="bg-[#FFD700] border-4 border-[#333333] shadow-[4px_4px_0_0_#333333] px-8 py-3 text-2xl active:translate-y-1 active:shadow-none transition-all"
              onClick={() => {
                setStatus('playing');
                EventBus.emit('start-game');
              }}
            >
              开始游戏
            </button>
          </div>
        </div>
      )}

      {/* HUD */}
      {(status === 'playing' || status === 'win' || status === 'lose') && (
        <div className="absolute top-4 left-4 z-10 flex items-center gap-2 bg-white/80 border-4 border-[#333333] px-4 py-2 rounded-none">
          <div className="w-8 h-8 bg-[#FFD700] border-2 border-[#333333] rounded-full flex items-center justify-center">
            ⭐
          </div>
          <span className="text-3xl">{score} / 5</span>
        </div>
      )}

      {/* Win Screen */}
      {status === 'win' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-10">
          <div className="bg-[#FFD700] border-4 border-[#333333] shadow-[8px_8px_0_0_#333333] p-8 flex flex-col items-center max-w-md w-[90%] text-center">
            <h1 className="text-5xl text-white mb-6" style={{textShadow: '3px 3px 0 #333333'}}>通关成功！</h1>
            <p className="text-white mb-8 text-xl" style={{textShadow: '1px 1px 0 #333333'}}>你收集了所有星星，真棒！</p>
            <button 
              className="bg-[#8CC63F] border-4 border-[#333333] shadow-[4px_4px_0_0_#333333] px-8 py-3 text-2xl text-white active:translate-y-1 active:shadow-none transition-all"
              onClick={() => {
                resetGame();
                EventBus.emit('restart-game');
              }}
            >
              再玩一次
            </button>
          </div>
        </div>
      )}

      {/* Lose Screen (Not used normally as death just respawns, but keeping if needed) */}
      {status === 'lose' && (
        <div className="absolute inset-0 flex flex-col items-center justify-center bg-black/40 z-10">
          <div className="bg-red-400 border-4 border-[#333333] shadow-[8px_8px_0_0_#333333] p-8 flex flex-col items-center max-w-md w-[90%] text-center">
            <h1 className="text-5xl text-white mb-6" style={{textShadow: '3px 3px 0 #333333'}}>游戏结束</h1>
            <button 
              className="bg-[#FFD700] border-4 border-[#333333] shadow-[4px_4px_0_0_#333333] px-8 py-3 text-2xl active:translate-y-1 active:shadow-none transition-all"
              onClick={() => {
                resetGame();
                EventBus.emit('restart-game');
              }}
            >
              重新开始
            </button>
          </div>
        </div>
      )}
    </div>
  );
}

import { Scene } from 'phaser';
import { EventBus } from '../EventBus';
import { useGameStore } from '../model/store';
import { 
  GAME_WIDTH, GAME_HEIGHT, TILE_SIZE, 
  PLAYER_SPEED, JUMP_VELOCITY, VARIABLE_JUMP_MULTIPLIER,
  COYOTE_TIME, JUMP_BUFFER_TIME, STARS_TO_WIN
} from '../constants';

export class Game extends Scene {
  private player!: Phaser.Physics.Arcade.Sprite;
  private platforms!: Phaser.Physics.Arcade.StaticGroup;
  private enemies!: Phaser.Physics.Arcade.Group;
  private stars!: Phaser.Physics.Arcade.Group;
  private checkpoints!: Phaser.Physics.Arcade.Group;
  private endPoint!: Phaser.Physics.Arcade.Sprite;
  private cursors!: Phaser.Types.Input.Keyboard.CursorKeys;
  private spaceKey!: Phaser.Input.Keyboard.Key;

  // Jump Mechanics State
  private lastGroundedTime: number = 0;
  private lastJumpBufferTime: number = 0;
  private isJumping: boolean = false;
  private checkpointPos: {x: number, y: number} = {x: 100, y: GAME_HEIGHT - TILE_SIZE * 2};

  private gameStarted: boolean = false;

  constructor() {
    super('Game');
  }

  create() {
    // Setup Background
    const bg = this.add.tileSprite(0, 0, GAME_WIDTH, GAME_HEIGHT, 'bg_blue');
    bg.setOrigin(0, 0);

    // Initial setup before play starts
    this.createPlatforms();
    this.createPlayer();
    this.createEnemies();
    this.createItems();

    // Physics Colliders
    this.physics.add.collider(this.player, this.platforms);
    this.physics.add.collider(this.enemies, this.platforms);
    this.physics.add.collider(this.stars, this.platforms);

    // Triggers
    this.physics.add.overlap(this.player, this.enemies, this.hitEnemy, undefined, this);
    this.physics.add.overlap(this.player, this.stars, this.collectStar, undefined, this);
    this.physics.add.overlap(this.player, this.checkpoints, this.hitCheckpoint, undefined, this);
    this.physics.add.overlap(this.player, this.endPoint, this.hitEndpoint, undefined, this);

    // Input setup
    if (this.input.keyboard) {
      this.cursors = this.input.keyboard.createCursorKeys();
      this.spaceKey = this.input.keyboard.addKey(Phaser.Input.Keyboard.KeyCodes.SPACE);
      this.input.keyboard.addCapture('SPACE');
    }

    // React Events
    EventBus.on('start-game', this.startGame, this);
    EventBus.on('restart-game', this.restartGame, this);

    // Check initial state
    if (useGameStore.getState().status === 'playing') {
      this.startGame();
    }
  }

  createPlatforms() {
    this.platforms = this.physics.add.staticGroup();
    const w = GAME_WIDTH;
    const h = GAME_HEIGHT;
    const t = TILE_SIZE;

    const addPlatform = (x: number, y: number, widthTiles: number) => {
      // Draw graphic platform and attach physics
      const rect = this.add.rectangle(x + (widthTiles * t)/2, y + t/2, widthTiles * t, t, 0x8CC63F);
      rect.setStrokeStyle(4, 0x333333);
      this.platforms.add(rect);
    };

    // Floor
    addPlatform(0, h - t, Math.ceil(w / t));

    // Some jumps (using 64px grid alignment)
    addPlatform(t*3, h - t*3, 2);
    addPlatform(t*6, h - t*5, 3);
    addPlatform(t*2, h - t*7, 2);
    addPlatform(t*9, h - t*7, 2);
  }

  createPlayer() {
    this.player = this.physics.add.sprite(this.checkpointPos.x, this.checkpointPos.y, 'player_idle');
    this.player.setScale(2);

    const body = this.player.body as Phaser.Physics.Arcade.Body;
    body.setSize(20, 26);
    body.setOffset(6, 6);
    this.player.setCollideWorldBounds(true);

    // Setup Audio
    // Mute warning: If sounds don't play before user interaction, we might need a dummy play on click.
  }

  createEnemies() {
    this.enemies = this.physics.add.group();
    const t = TILE_SIZE;
    const h = GAME_HEIGHT;

    // Enemy 1
    const enemy1 = this.enemies.create(t*7.5, h - t*6, 'enemy_run') as Phaser.Physics.Arcade.Sprite;
    enemy1.setScale(2);
    enemy1.setVelocityX(100);
    enemy1.setData('dir', 1);
    enemy1.play('enemy_run');
    (enemy1.body as Phaser.Physics.Arcade.Body).setSize(20, 26).setOffset(6, 6);
  }

  createItems() {
    this.stars = this.physics.add.group({ allowGravity: false });
    const t = TILE_SIZE;
    const h = GAME_HEIGHT;

    const starCoords = [
      {x: t*4, y: h - t*4},
      {x: t*7.5, y: h - t*6}, // Above enemy patrol
      {x: t*2.5, y: h - t*8},
      {x: t*10, y: h - t*8},
      {x: t*11, y: h - t*2.5}
    ];

    starCoords.forEach(pos => {
      const star = this.stars.create(pos.x, pos.y, 'star') as Phaser.Physics.Arcade.Sprite;
      star.setScale(2);
      star.play('star_spin');
      (star.body as Phaser.Physics.Arcade.Body).setSize(16, 16).setOffset(8, 8);
    });

    this.checkpoints = this.physics.add.group({ allowGravity: false });
    const cp = this.checkpoints.create(t*6.5, h - t*5 - t/2, 'checkpoint_off') as Phaser.Physics.Arcade.Sprite;
    cp.setData('active', false);

    this.endPoint = this.physics.add.sprite(t*11, h - t*1.5, 'end_idle');
    (this.endPoint.body as Phaser.Physics.Arcade.Body).setAllowGravity(false);
  }

  startGame() {
    this.gameStarted = true;
    this.player.setActive(true).setVisible(true);
    this.player.body!.enable = true;
  }

  restartGame() {
    this.scene.restart();
  }

  hitEnemy(p: any, e: any) {
    if (!this.gameStarted) return;

    // Respawn to checkpoint
    this.player.setPosition(this.checkpointPos.x, this.checkpointPos.y);
    this.player.setVelocity(0, 0);
    this.player.play('player_hit');
    this.player.once('animationcomplete', () => {
      this.player.play('player_idle');
    });

    // Generate simple beep
    this.playTone(150, 'sawtooth', 0.1);
  }

  collectStar(p: any, s: any) {
    if (!this.gameStarted) return;

    const star = s as Phaser.Physics.Arcade.Sprite;
    star.body!.enable = false;
    star.play('star_collect');
    star.once('animationcomplete', () => {
      star.destroy();
    });

    useGameStore.getState().addScore(1);
    this.playTone(800, 'sine', 0.1);
  }

  hitCheckpoint(p: any, c: any) {
    if (!this.gameStarted) return;
    const cp = c as Phaser.Physics.Arcade.Sprite;
    if (!cp.getData('active')) {
      cp.setData('active', true);
      cp.play('checkpoint_activate');
      cp.once('animationcomplete', () => {
        cp.play('checkpoint_wave');
      });
      this.checkpointPos = { x: cp.x, y: cp.y };
      this.playTone(400, 'square', 0.1);
    }
  }

  hitEndpoint(p: any, e: any) {
    if (!this.gameStarted) return;

    if (useGameStore.getState().score >= STARS_TO_WIN) {
      this.gameStarted = false;
      this.player.setVelocity(0, 0);
      this.player.play('player_idle');

      const ep = e as Phaser.Physics.Arcade.Sprite;
      ep.play('end_press');

      this.playTone(1200, 'sine', 0.3);
      EventBus.emit('win');
    }
  }

  // Simple programmatic audio since assets are missing specific sound files
  playTone(freq: number, type: OscillatorType, duration: number) {
    try {
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.type = type;
      osc.frequency.setValueAtTime(freq, ctx.currentTime);
      gain.gain.setValueAtTime(0.1, ctx.currentTime);
      gain.gain.exponentialRampToValueAtTime(0.01, ctx.currentTime + duration);
      osc.connect(gain);
      gain.connect(ctx.destination);
      osc.start();
      osc.stop(ctx.currentTime + duration);
    } catch (e) {
      // Ignore if audio context fails
    }
  }

  update(time: number, delta: number) {
    if (!this.gameStarted) return;

    this.updatePlayerMovement(time);
    this.updateEnemies();
  }

  updatePlayerMovement(time: number) {
    const body = this.player.body as Phaser.Physics.Arcade.Body;
    const isGrounded = body.touching.down || body.blocked.down;

    if (isGrounded) {
      this.lastGroundedTime = time;
      this.isJumping = false;
    }

    // Horizontal Movement
    if (this.cursors.left.isDown) {
      body.setVelocityX(-PLAYER_SPEED);
      this.player.setFlipX(true);
      if (isGrounded && this.player.anims.currentAnim?.key !== 'player_run') {
        this.player.play('player_run', true);
      }
    } else if (this.cursors.right.isDown) {
      body.setVelocityX(PLAYER_SPEED);
      this.player.setFlipX(false);
      if (isGrounded && this.player.anims.currentAnim?.key !== 'player_run') {
        this.player.play('player_run', true);
      }
    } else {
      body.setVelocityX(0);
      if (isGrounded && this.player.anims.currentAnim?.key !== 'player_idle' && this.player.anims.currentAnim?.key !== 'player_hit') {
        this.player.play('player_idle', true);
      }
    }

    // Jump Input Buffer
    if (Phaser.Input.Keyboard.JustDown(this.spaceKey)) {
      this.lastJumpBufferTime = time;
    }

    // Jump Execution (Coyote Time + Jump Buffer)
    if (time - this.lastJumpBufferTime <= JUMP_BUFFER_TIME && time - this.lastGroundedTime <= COYOTE_TIME && !this.isJumping) {
      body.setVelocityY(JUMP_VELOCITY);
      this.isJumping = true;
      this.lastJumpBufferTime = 0; // consume buffer
      this.lastGroundedTime = 0; // consume grounded
      this.player.play('player_jump', true);
      this.playTone(600, 'square', 0.1);
    }

    // Variable Jump Height (release early to fall faster)
    if (this.isJumping && !this.spaceKey.isDown && body.velocity.y < 0) {
      body.setVelocityY(body.velocity.y * VARIABLE_JUMP_MULTIPLIER);
    }

    // Fall Animation
    if (!isGrounded && body.velocity.y > 0) {
      this.player.play('player_fall', true);
    }
  }

  updateEnemies() {
    this.enemies.children.iterate((c) => {
      const e = c as Phaser.Physics.Arcade.Sprite;
      const body = e.body as Phaser.Physics.Arcade.Body;

      // Simple patrol logic
      if (body.blocked.right || body.blocked.left) {
        e.setData('dir', e.getData('dir') * -1);
      }

      const dir = e.getData('dir');
      e.setVelocityX(100 * dir);
      e.setFlipX(dir < 0);

      // Keep on platform edge (prevent falling off)
      // This needs a raycaster or edge check, but we can do a simple bound check based on known platform limits
      if (e.x > GAME_WIDTH - TILE_SIZE*2) {
        e.setData('dir', -1);
      } else if (e.x < TILE_SIZE*6) {
         e.setData('dir', 1);
      }
      return true;
    });
  }

  shutdown() {
    EventBus.off('start-game', this.startGame, this);
    EventBus.off('restart-game', this.restartGame, this);
  }
}
